391→
392→function blockToPlainText(block: Block) {
393→  switch (block.type) {
394→    case "paragraph":
395→    case "heading":
396→    case "quote":
397→    case "code":
398→      return block.text;
399→    case "list":
400→      return block.items.join("\n");
401→    case "table":
402→      return [
403→        block.headers.join(" | "),
404→        ...block.rows.map((row) => row.join(" | ")),
405→      ].join("\n");
406→  }
407→}
408→
409→function summarizeSelection(
410→  sessionDetail: AdjustmentSessionDetail,
411→  job: ImportJob | undefined,
412→) {
413→  const { selection, targetFormat } = sessionDetail.session;
414→
415→  if (targetFormat === "markdown") {
416→    const markdown = job?.artifacts?.markdown ?? "";
417→    const lines = markdown.split("\n");
418→    const lineStart = selection.lineStart ?? 1;
419→    const lineEnd = selection.lineEnd ?? lineStart;
420→
421→    return {
422→      currentExcerpt:
423→        lines.slice(lineStart - 1, lineEnd).join("\n") ||
424→        selection.selectedText,
425→      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
426→      surrounding: {
427→        next: lines[lineEnd] ?? null,
428→        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
429→      },
430→    };
431→  }
432→
433→  const message = job?.conversation?.messages.find(
434→    (entry) => entry.id === selection.messageId,
435→  );
436→  const currentBlock = message?.blocks[selection.blockIndex];
437→  const previousBlock =
438→    selection.blockIndex > 0
439→      ? message?.blocks[selection.blockIndex - 1]
440→      : undefined;
441→  const nextBlock = message?.blocks[selection.blockIndex + 1];
442→
443→  return {
444→    currentExcerpt: currentBlock
445→      ? blockToPlainText(currentBlock)
446→      : selection.selectedText,
447→    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
448→    surrounding: {
449→      next: nextBlock ? blockToPlainText(nextBlock) : null,
450→      previous: previousBlock ? blockToPlainText(previousBlock) : null,
451→    },
452→  };
453→}
454→
455→function buildSelectionContext(input: RunAgentTurnInput) {
456→  const { activeRules, job, sessionDetail } = input;
457→  const { selection, targetFormat } = sessionDetail.session;
458→  const selectionContext = summarizeSelection(sessionDetail, job);
459→  const lines: string[] = [];
460→
461→  lines.push("## Ausgewählter Block");
462→  lines.push(`Format: ${targetFormat}`);
463→  lines.push(
464→    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockIndex: ${selection.blockIndex})`,
465→  );
466→  lines.push(
467→    `Rolle: ${selection.messageRole}, Nachricht ${selection.messageIndex + 1}`,
468→  );
469→  if (selection.lineStart != null) {
470→    lines.push(
471→      `Zeilen: ${selection.lineStart}-${selection.lineEnd ?? selection.lineStart}`,
472→    );
473→  }
474→  lines.push("");
475→  lines.push("Inhalt des ausgewählten Blocks:");
476→  lines.push("```");
477→  lines.push(selectionContext.currentExcerpt);
478→  lines.push("```");
479→
480→  if (selectionContext.surrounding.previous) {
481→    lines.push("");
482→    lines.push("Block davor:");
483→    lines.push(`> ${selectionContext.surrounding.previous.slice(0, 200)}`);
484→  }
485→  if (selectionContext.surrounding.next) {
486→    lines.push("");
487→    lines.push("Block danach:");
488→    lines.push(`> ${selectionContext.surrounding.next.slice(0, 200)}`);
489→  }
490→
491→  const active = activeRules
492→    .filter((rule) => rule.status === "active")
493→    .slice(0, 8);
494→  if (active.length > 0) {
495→    lines.push("");
496→    lines.push("## Bereits aktive Regeln");
497→    for (const rule of active) {
498→      const selectorStr = rule.selector
499→        ? JSON.stringify(rule.selector)
500→        : "(kein Selektor)";
501→      lines.push(
502→        `- [${rule.id}] ${rule.instruction ?? "(keine Beschreibung)"} — Selektor: ${selectorStr}`,
503→      );
504→    }
505→  }
506→
507→  return lines.join("\n");
508→}
