510→type InputMessage = {
511→  content: Array<{ text: string; type: "input_text" }>;
512→  role: "system" | "user" | "assistant";
513→};
514→
515→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
516→  const targetFormat = input.sessionDetail.session.targetFormat;
517→  const messages: InputMessage[] = [
518→    {
519→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
520→      role: "system",
521→    },
522→    {
523→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
524→      role: "user",
525→    },
526→  ];
527→
528→  // Add session messages as real multi-turn conversation so the model
529→  // understands the full dialog history and can reference prior turns.
530→  for (const msg of input.sessionDetail.messages) {
531→    messages.push({
532→      content: [{ text: msg.content, type: "input_text" }],
533→      role: msg.role === "user" ? "user" : "assistant",
534→    });
535→  }
536→
537→  return messages;
538→}
