540→// ---------------------------------------------------------------------------
541→// OpenAI helpers
542→// ---------------------------------------------------------------------------
543→
544→function isRecord(value: unknown): value is Record<string, unknown> {
545→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
546→}
547→
548→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
549→  if (!Array.isArray(payload.output)) {
550→    return [];
551→  }
552→
553→  return payload.output.flatMap((item) => {
554→    if (!isRecord(item) || item.type !== "function_call") {
555→      return [];
556→    }
557→
558→    const callId = typeof item.call_id === "string" ? item.call_id : null;
559→    const name = typeof item.name === "string" ? item.name : null;
560→    const args = typeof item.arguments === "string" ? item.arguments : null;
561→
562→    if (!callId || !name || !args) {
563→      return [];
564→    }
565→
566→    return [{ arguments: args, callId, name }];
567→  });
568→}
569→
570→function extractAssistantMessage(payload: ResponsesPayload) {
571→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
572→    return payload.output_text.trim();
573→  }
574→
575→  if (!Array.isArray(payload.output)) {
576→    return "";
577→  }
578→
579→  return payload.output
580→    .flatMap((item) => {
581→      if (
582→        !isRecord(item) ||
583→        item.type !== "message" ||
584→        item.role !== "assistant"
585→      ) {
586→        return [];
587→      }
588→
589→      const content = item.content;
590→      if (!Array.isArray(content)) {
591→        return [];
592→      }
593→
594→      return content.flatMap((entry) => {
595→        if (!isRecord(entry) || entry.type !== "output_text") {
596→          return [];
597→        }
598→
599→        return typeof entry.text === "string" && entry.text.trim()
600→          ? [entry.text.trim()]
601→          : [];
602→      });
603→    })
604→    .join("\n")
605→    .trim();
606→}
