608→async function requestOpenAiResponse(
609→  body: Record<string, unknown>,
610→  config: ReturnType<typeof readAdjustmentAiConfig>,
611→) {
612→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
613→    method: "POST",
614→    headers: {
615→      "Content-Type": "application/json",
616→      Authorization: `Bearer ${config.openai?.apiKey}`,
617→    },
618→    body: JSON.stringify({
619→      model: config.model,
620→      reasoning: { effort: "low" },
621→      store: true,
622→      ...body,
623→    }),
624→    signal: AbortSignal.timeout(config.timeoutMs),
625→  });
626→
627→  if (!response.ok) {
628→    const errorText = await response.text();
629→    throw new AgentUnavailableError(
630→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
631→    );
632→  }
633→
634→  return (await response.json()) as ResponsesPayload;
635→}
