640→
641→function validateEffect(effect: unknown): {
642→  ok: boolean;
643→  data?: Record<string, unknown>;
644→  error?: string;
645→} {
646→  const result = customStyleEffectSchema.safeParse(effect);
647→  if (result.success) {
648→    return { ok: true, data: result.data as Record<string, unknown> };
649→  }
650→
651→  const issues = result.error.issues
652→    .map((i) => `${i.path.join(".")}: ${i.message}`)
653→    .join("; ");
654→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
655→}
656→
657→async function executeToolCall(
658→  call: FunctionCallItem,
659→  callbacks: RunAgentTurnInput["callbacks"],
660→  actions: ActionRecord[],
661→): Promise<string> {
662→  let args: Record<string, unknown>;
663→  try {
664→    args = JSON.parse(call.arguments) as Record<string, unknown>;
665→  } catch {
666→    return JSON.stringify({
667→      ok: false,
668→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
669→    });
670→  }
671→
672→  if (call.name === "create_rule") {
673→    const effectValidation = validateEffect(args.effect);
674→    if (!effectValidation.ok) {
675→      return JSON.stringify({ ok: false, error: effectValidation.error });
676→    }
677→
678→    try {
679→      const { ruleId } = await callbacks.onCreateRule({
680→        selector: args.selector as Record<string, unknown>,
681→        effect: effectValidation.data as Record<string, unknown>,
682→        description: String(args.description ?? ""),
683→      });
684→      actions.push({ type: "created", ruleId });
685→      return JSON.stringify({ ok: true, ruleId });
686→    } catch (error) {
687→      return JSON.stringify({
688→        ok: false,
689→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
690→      });
691→    }
692→  }
693→
694→  if (call.name === "update_rule") {
695→    const effectValidation = validateEffect(args.effect);
696→    if (!effectValidation.ok) {
697→      return JSON.stringify({ ok: false, error: effectValidation.error });
698→    }
699→
700→    const ruleId = String(args.ruleId ?? "");
701→
702→    try {
703→      await callbacks.onUpdateRule({
704→        ruleId,
705→        effect: effectValidation.data as Record<string, unknown>,
706→        description:
707→          typeof args.description === "string" ? args.description : undefined,
708→      });
709→      actions.push({ type: "updated", ruleId });
710→      return JSON.stringify({ ok: true, ruleId });
711→    } catch (error) {
712→      return JSON.stringify({
713→        ok: false,
714→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
715→      });
716→    }
717→  }
718→
719→  if (call.name === "delete_rule") {
720→    const ruleId = String(args.ruleId ?? "");
721→
722→    try {
723→      await callbacks.onDeleteRule(ruleId);
724→      actions.push({ type: "deleted", ruleId });
725→      return JSON.stringify({ ok: true, ruleId });
726→    } catch (error) {
727→      return JSON.stringify({
728→        ok: false,
729→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
730→      });
731→    }
732→  }
733→
734→  return JSON.stringify({
735→    ok: false,
736→    error: `Unbekannter Tool-Call: ${call.name}`,
737→  });
738→}
