740→// ---------------------------------------------------------------------------
741→// Main agent turn
742→// ---------------------------------------------------------------------------
743→
744→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
745→  assistantMessage: string;
746→  actions: ActionRecord[];
747→}> {
748→  const config = readAdjustmentAiConfig();
749→
750→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
751→    throw new AgentUnavailableError(
752→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
753→    );
754→  }
755→
756→  const actions: ActionRecord[] = [];
757→
758→  const inputMessages = buildInputMessages(input);
759→
760→  let payload = await requestOpenAiResponse(
761→    {
762→      input: inputMessages,
763→      tool_choice: "auto",
764→      tools: buildTools(),
765→    },
766→    config,
767→  );
768→
769→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
770→    const functionCalls = extractFunctionCalls(payload);
771→    if (functionCalls.length === 0) {
772→      break;
773→    }
774→
775→    if (!payload.id) {
776→      throw new Error(
777→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
778→      );
779→    }
780→
781→    const toolOutputs = [];
782→
783→    for (const call of functionCalls) {
784→      const result = await executeToolCall(call, input.callbacks, actions);
785→      toolOutputs.push({
786→        type: "function_call_output",
787→        call_id: call.callId,
788→        output: result,
789→      });
790→    }
791→
792→    payload = await requestOpenAiResponse(
793→      {
794→        input: toolOutputs,
795→        previous_response_id: payload.id,
796→        tool_choice: "auto",
797→        tools: buildTools(),
798→      },
799→      config,
800→    );
801→  }
802→
803→  const rawMessage = extractAssistantMessage(payload);
804→  let assistantMessage: string;
805→
806→  if (rawMessage) {
807→    assistantMessage = rawMessage;
808→  } else if (actions.length > 0) {
809→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
810→  } else {
811→    // The AI returned no text and took no actions — retry once with an
812→    // explicit nudge so the user sees an actual question instead of a
813→    // generic placeholder.
814→    const retryPayload = await requestOpenAiResponse(
815→      {
816→        input: [
817→          ...inputMessages,
818→          {
819→            content: [
820→              {
821→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
822→                type: "input_text",
823→              },
824→            ],
825→            role: "user",
826→          },
827→        ],
828→        tool_choice: "none",
829→        tools: buildTools(),
830→      },
831→      config,
832→    );
833→
834→    assistantMessage =
835→      extractAssistantMessage(retryPayload) ||
836→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
837→  }
838→
839→  return { assistantMessage, actions };
840→}
