+      { type: "paragraph", text: "Edited assistant response" },
+    ];
+    const edits = [
+      createEditEntry("msg-1", editedBlocks1),
+      createEditEntry("msg-2", editedBlocks2),
+    ];
+
+    const result = mergeEditsIntoConversation(conversation, edits);
