 71→export function activateSnapshot(snapshotId: string): ConversationSnapshot {
 72→  return withTransaction(() => {
 73→    const snapshot = db
 74→      .select()
 75→      .from(conversationSnapshots)
 76→      .where(eq(conversationSnapshots.id, snapshotId))
 77→      .get();
 78→
 79→    if (!snapshot) {
 80→      throw new Error(`Snapshot not found: ${snapshotId}`);
 81→    }
 82→
 83→    const now = new Date().toISOString();
 84→
 85→    // Deactivate all snapshots of the same import
