 87→      .set({ isActive: 0, updatedAt: now })
 88→      .where(eq(conversationSnapshots.importId, snapshot.importId))
 89→      .run();
 90→
 91→    // Activate this snapshot
 92→    db.update(conversationSnapshots)
 93→      .set({ isActive: 1, updatedAt: now })
 94→      .where(eq(conversationSnapshots.id, snapshotId))
 95→      .run();
 96→
 97→    const updated = db
 98→      .select()
 99→      .from(conversationSnapshots)
100→      .where(eq(conversationSnapshots.id, snapshotId))
101→      .get();
102→
103→    if (!updated) {
104→      throw new Error(`Snapshot not found after activation: ${snapshotId}`);
105→    }
106→
107→    return toApiSnapshot(updated);
108→  });
