100→export function applyMarkdownRules(content: string, rules: FormatRule[]) {
101→  const lines = content.split("\n");
102→  const nextLines = [...lines];
103→
104→  for (const rule of rules) {
105→    if (rule.status !== "active") {
106→      continue;
107→    }
108→
109→    const parsedSelector = ruleSelectorSchema.safeParse(rule.selector);
110→    const parsedEffect = ruleEffectSchema.safeParse(rule.compiledRule);
111→
112→    if (!parsedSelector.success || !parsedEffect.success) {
113→      continue;
114→    }
115→
116→    const selector = parsedSelector.data;
117→    const effect = normalizeLegacyEffect(parsedEffect.data);
118→
119→    const strategy = "strategy" in selector ? selector.strategy : undefined;
120→
121→    if (strategy === "compound") {
122→      const transform = effect.markdownTransform;
123→      if (!transform) continue;
