125→      // Compound in Markdown: textPattern match on each line
126→      // blockType/messageRole/context not relevant for Markdown (line-based only)
127→      const textPattern =
128→        "textPattern" in selector ? (selector as any).textPattern : null;
129→
130→      for (let index = 0; index < nextLines.length; index += 1) {
131→        const line = nextLines[index] ?? "";
132→
133→        // If textPattern set: only transform matching lines
134→        if (textPattern) {
135→          try {
136→            if (!new RegExp(textPattern).test(line)) continue;
137→          } catch {
138→            continue;
139→          }
140→        }
141→
142→        // Apply transform (same switch logic as for exact)
