1590→+export function activateSnapshot(snapshotId: string): ConversationSnapshot {
1591→+  return withTransaction(() => {
1592→+    const snapshot = db
1593→+      .select()
1594→+      .from(conversationSnapshots)
1595→+      .where(eq(conversationSnapshots.id, snapshotId))
1596→+      .get();
1597→+
1598→+    if (!snapshot) {
1599→+      throw new Error(`Snapshot not found: ${snapshotId}`);
1600→+    }
1601→+
1602→+    const now = new Date().toISOString();
1603→+
1604→+    // Deactivate all snapshots of the same import
1605→+    db.update(conversationSnapshots)
1606→+      .set({ isActive: 0, updatedAt: now })
1607→+      .where(eq(conversationSnapshots.importId, snapshot.importId))
1608→+      .run();
1609→+
1610→+    // Activate this snapshot
1611→+    db.update(conversationSnapshots)
1612→+      .set({ isActive: 1, updatedAt: now })
1613→+      .where(eq(conversationSnapshots.id, snapshotId))
1614→+      .run();
1615→+
1616→+    const updated = db
1617→+      .select()
1618→+      .from(conversationSnapshots)
1619→+      .where(eq(conversationSnapshots.id, snapshotId))
1620→+      .get();
1621→+
1622→+    if (!updated) {
1623→+      throw new Error(`Snapshot not found after activation: ${snapshotId}`);
1624→+    }
1625→+
1626→+    return toApiSnapshot(updated);
1627→+  });
