1662→+    .from(conversationSnapshots)
1663→+    .where(eq(conversationSnapshots.id, snapshotId))
1664→+    .get();
1665→+
1666→+  if (!updated) {
1667→+    throw new Error(`Snapshot not found: ${snapshotId}`);
1668→+  }
1669→+
1670→+  return toApiSnapshot(updated);
