 45→type ActiveStage = {
 46→  detail: string;
 47→  label: string;
 48→} | null;
 49→
 50→type FormatWorkspaceProps = {
 51→  activeStage: ActiveStage;
 52→  elapsedTime: string;
 53→  job: ImportJob;
 54→  view: ViewMode;
 55→  onViewChange: (view: ViewMode) => void;
 56→};
 57→
 58→function _describeSelectionLabel(selection: AdjustmentSelection) {
 59→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 60→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 61→  }
 62→
 63→  return formatMessageBlockLabel(
 64→    selection.messageRole,
 65→    selection.messageIndex + 1,
 66→    selection.blockType,
 67→  );
 68→}
 69→
 70→function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 71→  if (!job.artifacts) {
 72→    return "Artefakt ist noch nicht verfügbar.";
 73→  }
 74→
 75→  switch (view) {
 76→    case "markdown":
 77→      return job.artifacts.markdown;
 78→    case "handover":
 79→      return job.artifacts.handover;
 80→    case "json":
 81→      return job.artifacts.json;
 82→  }
 83→}
 84→
 85→export function FormatWorkspace({
 86→  activeStage,
 87→  elapsedTime,
 88→  job,
 89→  view,
 90→  onViewChange,
 91→}: FormatWorkspaceProps) {
 92→  const isAdjustableView = adjustableViews.has(view);
 93→
 94→  const session = useAdjustmentSession(view, job.id);
 95→  const rules = useFormatRules(view, job.id);
 96→  const snapshots = useSnapshots(job.id);
 97→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 98→  const resolvedMessages = useResolvedConversation(
 99→    job.conversation,
100→    messageEdits.editedMessagesMap,
101→  );
102→  const autoSnapshot = useAutoSnapshot({
103→    activeSnapshot: snapshots.activeSnapshot,
104→    create: snapshots.create,
105→    activate: snapshots.activate,
106→  });
107→  const deletion = useMessageDeletion(job.id);
108→  const deletionToast = useDeletionToast();
109→  const [editMode, setEditMode] = useState<EditMode>("view");
110→
111→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
112→  const handleEditModeChange = useCallback(
113→    (mode: EditMode) => {
114→      if (mode === "edit" && session.adjustModeEnabled) {
115→        session.toggleAdjustMode();
116→      }
117→      setEditMode(mode);
118→    },
119→    [session],
120→  );
121→
122→  const handleToggleAdjustMode = useCallback(() => {
123→    if (!session.adjustModeEnabled && editMode === "edit") {
124→      setEditMode("view");
125→    }
126→    session.toggleAdjustMode();
127→  }, [session, editMode]);
128→
129→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
130→
131→  // beforeunload warning when unsaved edits exist
132→  useEffect(() => {
133→    if (!messageEdits.isSaving) return;
134→    const handler = (e: BeforeUnloadEvent) => {
135→      e.preventDefault();
136→    };
137→    window.addEventListener("beforeunload", handler);
138→    return () => window.removeEventListener("beforeunload", handler);
139→  }, [messageEdits.isSaving]);
140→
141→  const handleBlocksChange = useCallback(
142→    (messageId: string, blocks: Block[]) => {
143→      void autoSnapshot.ensureSnapshot().then((ready) => {
144→        if (ready) {
145→          messageEdits.saveEdit(messageId, blocks);
146→        }
147→      });
148→    },
149→    [autoSnapshot, messageEdits],
150→  );
151→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
152→  const [deleteDialog, setDeleteDialog] = useState<{
153→    messageId: string;
154→    isRound: boolean;
155→    preview: string;
156→  } | null>(null);
157→  const popover = useAdjustmentPopover();
158→
159→  const handleDeleteMessage = useCallback(
160→    (messageId: string) => {
161→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
162→      const preview =
163→        msg?.blocks
164→          .map((b) => ("text" in b ? b.text : b.type))
165→          .join(" ")
166→          .slice(0, 200) ?? messageId;
167→      setDeleteDialog({ messageId, isRound: false, preview });
168→    },
169→    [job.conversation?.messages],
170→  );
171→
172→  const handleDeleteRound = useCallback(
173→    (messageId: string) => {
174→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
175→      const preview =
176→        msg?.blocks
177→          .map((b) => ("text" in b ? b.text : b.type))
178→          .join(" ")
179→          .slice(0, 200) ?? messageId;
180→      setDeleteDialog({ messageId, isRound: true, preview });
181→    },
182→    [job.conversation?.messages],
183→  );
184→
185→  const handleConfirmDelete = useCallback(
186→    async (reason?: string) => {
187→      if (!deleteDialog) return;
188→      const { messageId, isRound } = deleteDialog;
189→      setDeleteDialog(null);
190→      if (isRound) {
191→        const result = await deletion.deleteRound(messageId, reason);
192→        deletionToast.showDeletedToast(messageId, true, result.length);
193→      } else {
194→        await deletion.deleteMessage(messageId, reason);
195→        deletionToast.showDeletedToast(messageId, false);
196→      }
197→    },
198→    [deleteDialog, deletion, deletionToast],
199→  );
200→
201→  const handleUndoDelete = useCallback(async () => {
202→    if (!deletionToast.toast) return;
203→    await deletion.restoreMessage(deletionToast.toast.messageId);
204→    deletionToast.dismissToast();
205→  }, [deletion, deletionToast]);
206→
207→  const mergedRef = useCallback(
208→    (node: HTMLElement | null) => {
209→      (
210→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
211→      ).current = node;
212→      (
213→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
214→      ).current = node;
215→    },
216→    [session.sectionRef, popover.containerRef],
217→  );
218→
219→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
220→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
221→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
222→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
223→  const displayedMarkdown = useMemo(() => {
224→    if (view !== "markdown") return artifact;
225→    try {
226→      return applyMarkdownRules(artifact, rules.activeRules);
227→    } catch {
228→      return artifact;
229→    }
230→  }, [artifact, rules.activeRules, view]);
231→
232→  const resolvedConversation = useMemo(() => {
233→    if (!job.conversation) return undefined;
234→    return {
235→      ...job.conversation,
236→      messages: resolvedMessages.map((rm) => ({
237→        id: rm.id,
238→        role: rm.role,
239→        blocks: rm.blocks,
240→      })),
241→    };
242→  }, [job.conversation, resolvedMessages]);
243→
244→  const readerEffectsMap = useMemo(
245→    () =>
246→      view === "reader" && resolvedConversation
247→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
248→        : new Map(),
249→    [rules.activeRules, resolvedConversation, view],
250→  );
251→
252→  const handleCopyMessage = useCallback(
253→    (messageId: string) => {
254→      const msg = resolvedConversation?.messages.find(
255→        (m) => m.id === messageId,
256→      );
257→      if (!msg) return;
258→      void copyMessageToClipboard(msg, view, msg.blocks);
259→    },
260→    [resolvedConversation, view],
261→  );
262→
263→  const [copySuccess, setCopySuccess] = useState(false);
264→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
265→
266→  const handleCopyAll = useMemo(() => {
267→    const doCopy = async (content: string, isHtml: boolean) => {
268→      try {
269→        if (isHtml) {
270→          const blob = new Blob([content], { type: "text/html" });
271→          const plainBlob = new Blob([content], { type: "text/plain" });
272→          await navigator.clipboard.write([
273→            new ClipboardItem({
274→              "text/html": blob,
275→              "text/plain": plainBlob,
276→            }),
277→          ]);
278→        } else {
279→          await navigator.clipboard.writeText(content);
280→        }
281→        clearTimeout(copyTimeoutRef.current);
282→        setCopySuccess(true);
283→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
284→      } catch {
285→        // Fallback: silently fail
286→      }
287→    };
288→
289→    if (view === "markdown") {
290→      return () => {
291→        void doCopy(displayedMarkdown, false);
292→      };
293→    }
294→    if (view === "reader" && resolvedConversation) {
295→      return () => {
296→        const html = buildReaderHtml(
297→          resolvedConversation,
298→          readerEffectsMap,
299→          resolvedConversation.title ?? `export-${job.id}`,
300→        );
301→        void doCopy(html, true);
302→      };
303→    }
304→    if ((view === "handover" || view === "json") && artifact) {
305→      return () => {
306→        void doCopy(artifact, false);
307→      };
308→    }
309→    return undefined;
310→  }, [
311→    view,
312→    displayedMarkdown,
313→    job.id,
314→    resolvedConversation,
315→    readerEffectsMap,
316→    artifact,
317→  ]);
318→
319→  const handleDownload = useMemo(() => {
320→    if (view === "markdown") {
321→      return () => {
322→        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
323→        const url = URL.createObjectURL(blob);
324→        const a = document.createElement("a");
325→        a.href = url;
326→        a.download = `export-${job.id}.md`;
327→        document.body.appendChild(a);
328→        a.click();
329→        document.body.removeChild(a);
330→        setTimeout(() => URL.revokeObjectURL(url), 100);
331→      };
332→    }
333→    if (view === "reader" && resolvedConversation) {
334→      return () => {
335→        const html = buildReaderHtml(
336→          resolvedConversation,
337→          readerEffectsMap,
338→          resolvedConversation.title ?? `export-${job.id}`,
339→        );
340→        const blob = new Blob([html], { type: "text/html" });
341→        const url = URL.createObjectURL(blob);
342→        const a = document.createElement("a");
343→        a.href = url;
344→        a.download = `export-${job.id}.html`;
345→        document.body.appendChild(a);
346→        a.click();
347→        document.body.removeChild(a);
348→        setTimeout(() => URL.revokeObjectURL(url), 100);
349→      };
350→    }
351→    if ((view === "handover" || view === "json") && artifact) {
352→      return () => {
353→        const ext = view === "json" ? "json" : "md";
354→        const blob = new Blob([artifact], { type: "text/plain" });
355→        const url = URL.createObjectURL(blob);
356→        const a = document.createElement("a");
357→        a.href = url;
358→        a.download = `export-${job.id}.${ext}`;
359→        document.body.appendChild(a);
360→        a.click();
361→        document.body.removeChild(a);
362→        setTimeout(() => URL.revokeObjectURL(url), 100);
363→      };
364→    }
365→    return undefined;
366→  }, [
367→    view,
368→    displayedMarkdown,
369→    job.id,
370→    resolvedConversation,
371→    readerEffectsMap,
372→    artifact,
373→  ]);
374→  const showPopover =
375→    session.adjustModeEnabled &&
376→    Boolean(session.activeSelection) &&
377→    Boolean(session.activeAnchor);
378→
379→  const popoverCallbacksRef = useRef({
380→    handleDiscardSession: session.handleDiscardSession,
381→    activeSessionDetail: session.activeSessionDetail,
382→    handleRejectLastChange: rules.handleRejectLastChange,
383→    setReplyVisible: session.setReplyVisible,
384→  });
385→  popoverCallbacksRef.current = {
386→    handleDiscardSession: session.handleDiscardSession,
387→    activeSessionDetail: session.activeSessionDetail,
388→    handleRejectLastChange: rules.handleRejectLastChange,
389→    setReplyVisible: session.setReplyVisible,
390→  };
391→
392→  const handlePopoverClose = useCallback(() => {
393→    popoverCallbacksRef.current.handleDiscardSession();
394→  }, []);
395→
396→  const handleRejectLastChange = useCallback(() => {
397→    const {
398→      activeSessionDetail,
399→      handleRejectLastChange: reject,
400→      setReplyVisible,
401→    } = popoverCallbacksRef.current;
402→    if (activeSessionDetail) {
403→      void reject(activeSessionDetail).then((success) => {
404→        if (success) setReplyVisible(false);
405→      });
406→    }
407→  }, []);
408→
409→  const sessionError =
410→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
411→
412→  const viewErrorFallback = (_error: Error, reset: () => void) => (
413→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
414→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
415→      <button
416→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
417→        type="button"
418→        onClick={reset}
419→      >
420→        {miscLabels.retryButton}
421→      </button>
422→    </div>
423→  );
424→
425→  return (
426→    <section
427→      ref={mergedRef}
428→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
429→    >
430→      <StatusHeader
431→        activeStage={activeStage}
432→        elapsedTime={elapsedTime}
433→        job={job}
434→      />
435→
436→      {job.warnings.length > 0 ? (
437→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
438→          {job.warnings[0]}
439→        </div>
440→      ) : null}
441→
442→      {job.status === "failed" ? (
443→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
444→          <p className="font-medium">{miscLabels.importFailed}</p>
445→          {job.errorStage && job.errorStage !== "done" && (
446→            <p className="text-sm mt-1">
447→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
448→            </p>
449→          )}
450→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
451→        </div>
452→      ) : job.status === "queued" || job.status === "running" ? (
453→        <LoadingStateBlock stageDetail={activeStage?.detail} />
454→      ) : (
455→        <div className="space-y-4">
456→          <CompletedToolbar
457→            adjustModeEnabled={session.adjustModeEnabled}
458→            copySuccess={copySuccess}
459→            editMode={editMode}
460→            isAdjustableView={isAdjustableView}
461→            rules={rules}
462→            view={view}
463→            onCopyAll={handleCopyAll}
464→            onDownloadMarkdown={handleDownload}
465→            onEditModeChange={handleEditModeChange}
466→            onToggleAdjustMode={handleToggleAdjustMode}
467→            onViewChange={onViewChange}
468→            deletionsCount={deletion.deletionsCount}
469→            showDeleted={deletion.showDeleted}
470→            snapshotCount={snapshots.snapshots.length}
471→            onVersionsClick={() => setVersionsModalOpen(true)}
472→            onToggleShowDeleted={() =>
473→              deletion.setShowDeleted(!deletion.showDeleted)
474→            }
475→          />
476→
477→          {sessionError && !session.adjustModeEnabled ? (
478→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
479→              {sessionError}
480→            </div>
481→          ) : null}
482→
483→          {view === "reader" ? (
484→            <ErrorBoundary fallback={viewErrorFallback}>
485→              <div className="space-y-2">
486→                <div className="flex justify-end">
487→                  <SaveIndicator
488→                    isSaving={messageEdits.isSaving}
489→                    hasEdits={hasEdits}
490→                  />
491→                </div>
492→                <ReaderView
493→                  activeRules={rules.activeRules}
494→                  conversation={resolvedConversation}
495→                  adjustModeEnabled={session.adjustModeEnabled}
496→                  editMode={editMode === "edit"}
497→                  effectsMap={readerEffectsMap}
498→                  highlightedRuleId={rules.hoveredRuleId}
499→                  selectedBlock={
500→                    view === "reader" ? session.activeSelection : null
501→                  }
502→                  onSelectBlock={session.handleSelectionChange}
503→                  deletedMessageIds={deletion.deletedMessageIds}
504→                  showDeleted={deletion.showDeleted}
505→                  onBlocksChange={handleBlocksChange}
506→                  onCopyMessage={handleCopyMessage}
507→                  onDeleteMessage={handleDeleteMessage}
508→                  onDeleteRound={handleDeleteRound}
509→                  onRestoreMessage={deletion.restoreMessage}
510→                />
511→              </div>
512→            </ErrorBoundary>
513→          ) : view === "markdown" ? (
514→            <ErrorBoundary fallback={viewErrorFallback}>
515→              <MarkdownView
516→                activeRules={rules.activeRules}
517→                content={displayedMarkdown}
518→                adjustModeEnabled={session.adjustModeEnabled}
519→                highlightedRuleId={rules.hoveredRuleId}
520→                selectedRange={session.activeSelection}
521→                onSelectLines={session.handleSelectionChange}
522→              />
523→            </ErrorBoundary>
524→          ) : (
525→            <ErrorBoundary fallback={viewErrorFallback}>
526→              <ArtifactView content={artifact} />
527→            </ErrorBoundary>
528→          )}
529→
530→          {session.showGuide ? (
531→            <AdjustmentModeGuide
532→              view={view}
533→              onDismiss={() => session.setGuideDismissed(true)}
534→            />
535→          ) : null}
536→
537→          <ErrorBoundary
538→            fallback={
539→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
540→                {miscLabels.adjustmentLoadError}
541→              </div>
542→            }
543→          >
544→            <AdjustmentPopover
545→              anchor={session.activeAnchor ?? null}
546→              containerRef={session.sectionRef}
547→              draftMessage={session.activeDraftMessage}
548→              error={session.activeSessionError}
549→              isLoading={session.activeSessionLoading || session.isDiscarding}
550→              isSubmitting={session.isSubmitting}
551→              open={
552→                showPopover &&
553→                Boolean(session.activeSelection) &&
554→                Boolean(session.activeAnchor)
555→              }
556→              sessionDetail={session.activeSessionDetail}
557→              showReply={session.replyVisible}
558→              view={view}
559→              onClose={handlePopoverClose}
560→              onDraftMessageChange={session.handleDraftMessageChange}
561→              onRejectLastChange={handleRejectLastChange}
562→              onSubmitMessage={session.handleSubmitMessage}
563→            />
564→          </ErrorBoundary>
565→        </div>
566→      )}
567→
568→      {deleteDialog && (
569→        <DeleteMessageDialog
570→          messagePreview={deleteDialog.preview}
571→          isRound={deleteDialog.isRound}
572→          onConfirm={(reason) => {
573→            void handleConfirmDelete(reason);
574→          }}
575→          onCancel={() => setDeleteDialog(null)}
576→        />
577→      )}
578→
579→      {deletionToast.toast && (
580→        <UndoToast
581→          message={deletionToast.toast.message}
582→          onUndo={() => {
583→            void handleUndoDelete();
584→          }}
585→          onDismiss={deletionToast.dismissToast}
586→        />
587→      )}
588→
589→      <VersionsModal
590→        open={versionsModalOpen}
591→        onOpenChange={setVersionsModalOpen}
592→        snapshots={snapshots.snapshots}
593→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
594→        onActivate={(snapshotId) => {
595→          void snapshots.activate(snapshotId);
596→        }}
597→        onDeactivate={() => {
598→          void snapshots.deactivate();
599→        }}
600→        onCreate={(label) => {
601→          void snapshots.create(label);
602→        }}
603→        onRename={(snapshotId, label) => {
604→          void snapshots.rename(snapshotId, label);
605→        }}
606→        onDelete={(snapshotId) => {
607→          void snapshots.delete(snapshotId);
608→        }}
609→      />
610→    </section>
611→  );
612→}
