 72→export function EditableBlock({
 73→  block,
 74→  blockIndex,
 75→  messageId,
 76→  onBlockChange,
 77→  children,
 78→}: EditableBlockProps) {
 79→  const ref = useRef<HTMLDivElement>(null);
 80→
 81→  const handleBlur = useCallback(() => {
 82→    const element = ref.current;
 83→    if (!element) return;
 84→
 85→    const newBlock = readBlockFromDom(element, block);
 86→    onBlockChange(messageId, blockIndex, newBlock);
 87→  }, [block, blockIndex, messageId, onBlockChange]);
 88→
 89→  const handleKeyDown = useCallback(
 90→    (event: React.KeyboardEvent<HTMLDivElement>) => {
 91→      if (event.key === "Escape") {
 92→        event.currentTarget.blur();
 93→      }
 94→    },
 95→    [],
 96→  );
 97→
 98→  const handlePaste = useCallback(
 99→    (event: React.ClipboardEvent<HTMLDivElement>) => {
100→      event.preventDefault();
101→      const plainText = event.clipboardData.getData("text/plain");
102→      const selection = window.getSelection();
103→      if (selection && selection.rangeCount > 0) {
104→        const range = selection.getRangeAt(0);
105→        range.deleteContents();
106→        range.insertNode(document.createTextNode(plainText));
107→        range.collapse(false);
108→      }
109→    },
110→    [],
111→  );
112→
113→  const isCodeBlock = block.type === "code";
114→
115→  const isEmpty = useMemo(() => {
116→    if (
117→      block.type === "paragraph" ||
118→      block.type === "heading" ||
119→      block.type === "quote" ||
120→      block.type === "code"
121→    ) {
122→      return block.text === "";
123→    }
124→    return false;
125→  }, [block]);
126→
127→  const placeholderProps = isEmpty
128→    ? { "data-placeholder": "Text eingeben..." }
129→    : {};
130→
131→  return (
132→    /* biome-ignore lint/a11y/useSemanticElements: contentEditable div wraps arbitrary block content, not a simple text input */
133→    <div
134→      ref={ref}
135→      role="textbox"
136→      tabIndex={0}
137→      data-testid="editable-block"
138→      contentEditable
139→      suppressContentEditableWarning
140→      onBlur={handleBlur}
141→      onKeyDown={handleKeyDown}
142→      onPaste={handlePaste}
143→      className={cn(
144→        "outline-none rounded-md ring-0 focus:ring-1 focus:ring-blue-300 transition-shadow",
145→        isCodeBlock && "whitespace-pre-wrap",
146→        isEmpty &&
147→          "[&:empty]:before:content-[attr(data-placeholder)] [&:empty]:before:text-gray-400 [&:empty]:before:pointer-events-none",
148→      )}
149→      {...placeholderProps}
150→    >
151→      {children}
152→    </div>
153→  );
154→}
