 1→import type { ConversationSnapshot } from "@chat-exporter/shared";
 2→import { useCallback, useRef } from "react";
 3→
 4→type UseAutoSnapshotOptions = {
 5→  activeSnapshot: ConversationSnapshot | null;
 6→  create: (label: string) => Promise<ConversationSnapshot>;
 7→  activate: (snapshotId: string) => Promise<unknown>;
 8→};
 9→
10→/**
11→ * Ensures a snapshot exists and is active before an edit is saved.
12→ * On the first edit (when no snapshot is active), automatically creates
13→ * a "Bearbeitet" snapshot and activates it.
14→ */
15→export function useAutoSnapshot({
16→  activeSnapshot,
17→  create,
18→  activate,
19→}: UseAutoSnapshotOptions) {
20→  const creatingRef = useRef(false);
21→
22→  const ensureSnapshot = useCallback(async (): Promise<boolean> => {
23→    if (activeSnapshot) return true;
24→    if (creatingRef.current) return true;
25→
26→    creatingRef.current = true;
27→    try {
28→      const snapshot = await create("Bearbeitet");
29→      await activate(snapshot.id);
30→      return true;
31→    } catch {
32→      return false;
33→    } finally {
34→      creatingRef.current = false;
35→    }
36→  }, [activeSnapshot, create, activate]);
37→
38→  return { ensureSnapshot };
39→}
