6930→+import type { Block } from "@chat-exporter/shared";
6931→+import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
6932→+import { useCallback, useMemo, useRef } from "react";
6933→+
6934→+import { orpc } from "@/lib/orpc";
6935→+
6936→+const DEBOUNCE_MS = 500;
6937→+
6938→+export function useMessageEdits(importId: string, snapshotId?: string) {
6939→+  const queryClient = useQueryClient();
6940→+  const debounceTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
6941→+    new Map(),
6942→+  );
6943→+
6944→+  const editsQuery = useQuery({
6945→+    ...orpc.edits.listForSnapshot.queryOptions({
6946→+      input: { snapshotId: snapshotId as string },
6947→+    }),
6948→+    enabled: !!snapshotId,
6949→+  });
6950→+
6951→+  const invalidate = () =>
6952→+    queryClient.invalidateQueries({
6953→+      queryKey: orpc.edits.listForSnapshot.key(),
6954→+    });
6955→+
6956→+  const saveMutation = useMutation(
6957→+    orpc.edits.save.mutationOptions({
6958→+      onSuccess: () => invalidate(),
6959→+    }),
6960→+  );
6961→+
6962→+  const deleteMutation = useMutation(
6963→+    orpc.edits.delete.mutationOptions({
6964→+      onSuccess: () => invalidate(),
6965→+    }),
6966→+  );
6967→+
6968→+  const editedMessagesMap = useMemo(() => {
6969→+    const map = new Map<string, Block[]>();
6970→+    if (!editsQuery.data) return map;
6971→+    for (const edit of editsQuery.data) {
6972→+      map.set(edit.messageId, edit.editedBlocks);
6973→+    }
6974→+    return map;
6975→+  }, [editsQuery.data]);
6976→+
6977→+  const saveEdit = useCallback(
6978→+    (messageId: string, blocks: Block[], annotation?: string) => {
6979→+      if (!snapshotId) return;
6980→+
6981→+      const existing = debounceTimers.current.get(messageId);
6982→+      if (existing) clearTimeout(existing);
6983→+
6984→+      const timer = setTimeout(() => {
6985→+        debounceTimers.current.delete(messageId);
6986→+        saveMutation.mutate({
6987→+          importId,
6988→+          snapshotId,
6989→+          messageId,
6990→+          editedBlocks: blocks,
6991→+          annotation,
6992→+        });
6993→+      }, DEBOUNCE_MS);
6994→+
6995→+      debounceTimers.current.set(messageId, timer);
6996→+    },
6997→+    [importId, snapshotId, saveMutation.mutate],
6998→+  );
6999→+
7000→+  const deleteEdit = useCallback(
7001→+    (messageId: string) => {
7002→+      if (!snapshotId) return;
7003→+
7004→+      // Cancel any pending debounced save for this message
7005→+      const existing = debounceTimers.current.get(messageId);
7006→+      if (existing) {
7007→+        clearTimeout(existing);
7008→+        debounceTimers.current.delete(messageId);
7009→+      }
7010→+
7011→+      return deleteMutation.mutateAsync({
7012→+        importId,
7013→+        snapshotId,
7014→+        messageId,
7015→+      });
7016→+    },
7017→+    [importId, snapshotId, deleteMutation.mutateAsync],
7018→+  );
7019→+
7020→+  return {
7021→+    edits: editsQuery.data ?? [],
7022→+    editedMessagesMap,
7023→+    isLoading: editsQuery.isLoading,
7024→+    isSaving: saveMutation.isPending,
7025→+    isDeleting: deleteMutation.isPending,
7026→+    saveEdit,
7027→+    deleteEdit,
7028→+  };
7029→+}
