6887→+
6888→+type UseAutoSnapshotOptions = {
6889→+  activeSnapshot: ConversationSnapshot | null;
6890→+  create: (label: string) => Promise<ConversationSnapshot>;
6891→+  activate: (snapshotId: string) => Promise<unknown>;
6892→+};
