6894→+/**
6895→+ * Ensures a snapshot exists and is active before an edit is saved.
6896→+ * On the first edit (when no snapshot is active), automatically creates
6897→+ * a "Bearbeitet" snapshot and activates it.
6898→+ */
6899→+export function useAutoSnapshot({
6900→+  activeSnapshot,
6901→+  create,
6902→+  activate,
6903→+}: UseAutoSnapshotOptions) {
6904→+  const creatingRef = useRef(false);
6905→+
6906→+  const ensureSnapshot = useCallback(async (): Promise<boolean> => {
6907→+    if (activeSnapshot) return true;
6908→+    if (creatingRef.current) return true;
6909→+
6910→+    creatingRef.current = true;
6911→+    try {
6912→+      const snapshot = await create("Bearbeitet");
6913→+      await activate(snapshot.id);
6914→+      return true;
6915→+    } catch {
6916→+      return false;
6917→+    } finally {
6918→+      creatingRef.current = false;
6919→+    }
6920→+  }, [activeSnapshot, create, activate]);
6921→+
6922→+  return { ensureSnapshot };
6923→+}
