 69→  selection: AdjustmentSelection;
 70→}) {
 71→  const { activeRules, content, preview, selection } = props;
 72→  const previewRule = buildPreviewRule(preview);
 73→  const beforeContent = applyMarkdownRules(content, activeRules);
 74→  const afterContent = applyMarkdownRules(content, [
 75→    ...activeRules,
 76→    previewRule,
 77→  ]);
