 80→  const lineStart = selection.lineStart ?? 1;
 81→  const lineEnd = selection.lineEnd ?? lineStart;
 82→  const contextStart = Math.max(1, lineStart - 1);
 83→  const contextEnd = Math.min(afterLines.length, lineEnd + 1);
 84→  const lineNumbers = Array.from(
 85→    { length: contextEnd - contextStart + 1 },
 86→    (_, index) => contextStart + index,
 87→  );
