100→            return (
101→              <div
102→                key={`before-${lineNumber}`}
103→                className={cn(
104→                  "grid grid-cols-[auto_1fr] gap-3 rounded-lg px-2 py-1 font-mono text-xs text-zinc-100",
105→                  isSelectedLine
106→                    ? "bg-primary/15 ring-1 ring-primary/30"
107→                    : null,
108→                )}
109→              >
110→                <span className="select-none text-zinc-500">
111→                  {formatLineNumber(lineNumber)}
112→                </span>
113→                <span className="whitespace-pre-wrap break-words">
114→                  {beforeLines[lineNumber - 1] ?? ""}
