832→+
833→+/**
834→+ * Merges message edits into a conversation, returning a new Conversation
835→+ * with edited blocks replacing the originals. Does not mutate the input.
836→+ *
837→+ * When duplicate messageIds exist in edits, the last entry wins.
838→+ */
839→+export function mergeEditsIntoConversation(
840→+  conversation: Conversation,
841→+  edits: MessageEditEntry[],
842→+): Conversation {
843→+  if (edits.length === 0) return conversation;
844→+
845→+  const editMap = new Map<string, Block[]>();
846→+  for (const edit of edits) {
847→+    editMap.set(edit.messageId, JSON.parse(edit.editedBlocksJson));
848→+  }
849→+
850→+  return {
851→+    ...conversation,
852→+    messages: conversation.messages.map((msg) => {
853→+      const editedBlocks = editMap.get(msg.id);
854→+      if (editedBlocks) {
855→+        return { ...msg, blocks: editedBlocks };
856→+      }
857→+      return msg;
858→+    }),
859→+  };
860→+}
