  9→export function useMessageEdits(importId: string, snapshotId?: string) {
 10→  const queryClient = useQueryClient();
 11→  const debounceTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
 12→    new Map(),
 13→  );
 14→
 15→  const editsQuery = useQuery({
 16→    ...orpc.edits.listForSnapshot.queryOptions({
 17→      input: { snapshotId: snapshotId as string },
 18→    }),
 19→    enabled: !!snapshotId,
 20→  });
 21→
 22→  const invalidate = () =>
 23→    queryClient.invalidateQueries({
 24→      queryKey: orpc.edits.listForSnapshot.key(),
 25→    });
 26→
 27→  const saveMutation = useMutation(
 28→    orpc.edits.save.mutationOptions({
 29→      onSuccess: () => invalidate(),
 30→    }),
 31→  );
 32→
 33→  const deleteMutation = useMutation(
 34→    orpc.edits.delete.mutationOptions({
 35→      onSuccess: () => invalidate(),
 36→    }),
 37→  );
 38→
 39→  const editedMessagesMap = useMemo(() => {
 40→    const map = new Map<string, Block[]>();
 41→    if (!editsQuery.data) return map;
 42→    for (const edit of editsQuery.data) {
 43→      map.set(edit.messageId, edit.editedBlocks);
 44→    }
 45→    return map;
 46→  }, [editsQuery.data]);
 47→
 48→  const saveEdit = useCallback(
 49→    (messageId: string, blocks: Block[], annotation?: string) => {
 50→      if (!snapshotId) return;
 51→
 52→      const existing = debounceTimers.current.get(messageId);
 53→      if (existing) clearTimeout(existing);
 54→
 55→      const timer = setTimeout(() => {
 56→        debounceTimers.current.delete(messageId);
 57→        saveMutation.mutate({
 58→          importId,
 59→          snapshotId,
 60→          messageId,
 61→          editedBlocks: blocks,
 62→          annotation,
 63→        });
 64→      }, DEBOUNCE_MS);
 65→
 66→      debounceTimers.current.set(messageId, timer);
 67→    },
 68→    [importId, snapshotId, saveMutation.mutate],
 69→  );
 70→
 71→  const deleteEdit = useCallback(
 72→    (messageId: string) => {
 73→      if (!snapshotId) return;
 74→
 75→      // Cancel any pending debounced save for this message
 76→      const existing = debounceTimers.current.get(messageId);
 77→      if (existing) {
 78→        clearTimeout(existing);
 79→        debounceTimers.current.delete(messageId);
 80→      }
 81→
 82→      return deleteMutation.mutateAsync({
 83→        importId,
 84→        snapshotId,
 85→        messageId,
 86→      });
 87→    },
 88→    [importId, snapshotId, deleteMutation.mutateAsync],
 89→  );
 90→
 91→  return {
 92→    edits: editsQuery.data ?? [],
 93→    editedMessagesMap,
 94→    isLoading: editsQuery.isLoading,
 95→    isSaving: saveMutation.isPending,
 96→    isDeleting: deleteMutation.isPending,
 97→    saveEdit,
 98→    deleteEdit,
 99→  };
100→}
