 60→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 61→  }
 62→
 63→  return formatMessageBlockLabel(
 64→    selection.messageRole,
 65→    selection.messageIndex + 1,
 66→    selection.blockType,
 67→  );
 68→}
 69→
 70→function renderArtifact(view: Exclude<ViewMode, "reader">, job: ImportJob) {
 71→  if (!job.artifacts) {
 72→    return "Artefakt ist noch nicht verfügbar.";
 73→  }
 74→
 75→  switch (view) {
 76→    case "markdown":
 77→      return job.artifacts.markdown;
 78→    case "handover":
 79→      return job.artifacts.handover;
 80→    case "json":
 81→      return job.artifacts.json;
 82→  }
 83→}
