333→    if (view === "reader" && resolvedConversation) {
334→      return () => {
335→        const html = buildReaderHtml(
336→          resolvedConversation,
337→          readerEffectsMap,
338→          resolvedConversation.title ?? `export-${job.id}`,
339→        );
340→        const blob = new Blob([html], { type: "text/html" });
341→        const url = URL.createObjectURL(blob);
342→        const a = document.createElement("a");
343→        a.href = url;
344→        a.download = `export-${job.id}.html`;
