 26→export function resolveReaderBlockEffects(
 27→  rules: FormatRule[],
 28→  messageId: string,
 29→  blockIndex: number,
 30→  blockType: Block["type"],
 31→  blockText: string,
 32→  context?: ReaderMatchContext,
 33→) {
 34→  return rules
 35→    .filter(
 36→      (rule) =>
 37→        rule.status === "active" &&
 38→        matchesReaderRule(
 39→          rule,
 40→          messageId,
 41→          blockIndex,
 42→          blockType,
 43→          blockText,
 44→          context,
 45→        ),
 46→    )
 47→    .map((rule) => rule.compiledRule)
 48→    .filter((effect): effect is RuleEffect => effect !== undefined)
 49→    .map(normalizeLegacyEffect);
 50→}
