 3→export interface MessageEditEntry {
 4→  messageId: string;
 5→  editedBlocksJson: string;
 6→}
 7→
 8→/**
 9→ * Merges message edits into a conversation, returning a new Conversation
10→ * with edited blocks replacing the originals. Does not mutate the input.
11→ *
12→ * When duplicate messageIds exist in edits, the last entry wins.
13→ */
14→export function mergeEditsIntoConversation(
15→  conversation: Conversation,
16→  edits: MessageEditEntry[],
17→): Conversation {
18→  if (edits.length === 0) return conversation;
19→
20→  const editMap = new Map<string, Block[]>();
21→  for (const edit of edits) {
22→    editMap.set(edit.messageId, JSON.parse(edit.editedBlocksJson));
23→  }
24→
25→  return {
26→    ...conversation,
27→    messages: conversation.messages.map((msg) => {
28→      const editedBlocks = editMap.get(msg.id);
29→      if (editedBlocks) {
30→        return { ...msg, blocks: editedBlocks };
31→      }
32→      return msg;
33→    }),
34→  };
35→}
