225→    appendMessage: os.adjustments.appendMessage.handler(async ({ input }) => {
226→      const detail = getAdjustmentSessionDetail(input.sessionId);
227→
228→      if (!detail) {
229→        throw new ORPCError("NOT_FOUND", {
230→          message: "Anpassungssession nicht gefunden.",
231→        });
232→      }
233→
234→      // Phase 1 — Transaction: reopen (if needed) + append user message + reload detail
235→      const latestDetail = withTransaction(() => {
236→        const freshDetail = getAdjustmentSessionDetail(input.sessionId);
237→
238→        if (!freshDetail) {
239→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
240→            message: "Anpassungssession konnte nicht neu geladen werden.",
241→          });
242→        }
243→
244→        if (freshDetail.session.status === "applied") {
245→          reopenAdjustmentSession(input.sessionId);
246→        }
247→
248→        appendAdjustmentMessage(input.sessionId, "user", input.content);
249→
250→        const reloaded = getAdjustmentSessionDetail(input.sessionId);
251→
252→        if (!reloaded) {
253→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
254→            message: "Anpassungssession konnte nicht neu geladen werden.",
255→          });
256→        }
257→
258→        return reloaded;
259→      });
260→
261→      const activeRules = listFormatRules(
262→        detail.session.importId,
263→        detail.session.targetFormat,
264→      ).filter((rule: { status: string }) => rule.status === "active");
265→
266→      // Phase 2 — no wrapper: async AI call
267→      try {
268→        const job = getImportJob(detail.session.importId);
269→        const result = await runAgentTurn({
270→          sessionDetail: latestDetail,
271→          activeRules,
272→          job,
273→          callbacks: {
274→            onCreateRule: async ({ selector, effect, description }) => {
275→              const rule = createFormatRuleDirect({
276→                importId: latestDetail.session.importId,
277→                targetFormat: latestDetail.session.targetFormat,
278→                selector,
279→                effect: {
280→                  type: "custom_style" as const,
281→                  ...effect,
282→                  description,
283→                },
284→                instruction: description,
285→                sourceSessionId: input.sessionId,
286→              });
287→              return { ruleId: rule.id };
288→            },
289→            onUpdateRule: async ({ ruleId, effect, description }) => {
290→              updateFormatRuleEffect(
291→                ruleId,
292→                { type: "custom_style" as const, ...effect, description },
293→                description,
294→              );
295→            },
296→            onDeleteRule: async (ruleId) => {
297→              disableFormatRule(ruleId, latestDetail.session.importId);
298→            },
299→          },
300→        });
301→
302→        // Phase 3 — persist assistant message + events
303→        withTransaction(() => {
304→          appendAdjustmentMessage(
305→            input.sessionId,
306→            "assistant",
307→            result.assistantMessage,
308→          );
309→
310→          for (const action of result.actions) {
311→            recordAdjustmentEvent({
312→              importId: latestDetail.session.importId,
313→              ruleId: action.ruleId,
314→              sessionId: input.sessionId,
315→              targetFormat: latestDetail.session.targetFormat,
316→              type:
317→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
318→            });
319→          }
320→
321→          if (result.actions.length > 0) {
322→            markSessionApplied(input.sessionId);
323→          } else {
324→            recordAdjustmentEvent({
325→              importId: latestDetail.session.importId,
326→              sessionId: input.sessionId,
327→              targetFormat: latestDetail.session.targetFormat,
328→              type: "clarification_requested",
329→            });
330→          }
331→        });
332→      } catch (error) {
333→        if (error instanceof AgentUnavailableError) {
334→          throw new ORPCError("SERVICE_UNAVAILABLE", {
335→            message: error.message,
336→          });
337→        }
338→        if (error instanceof DOMException && error.name === "TimeoutError") {
339→          throw new ORPCError("GATEWAY_TIMEOUT", {
340→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
341→          });
342→        }
343→        throw new ORPCError("BAD_REQUEST", {
344→          message:
345→            error instanceof Error
346→              ? error.message
347→              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",
348→        });
349→      }
350→
351→      const nextDetail = getAdjustmentSessionDetail(input.sessionId);
352→
353→      if (!nextDetail) {
354→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
355→          message: "Anpassungssession konnte nicht neu geladen werden.",
356→        });
357→      }
358→
359→      return nextDetail;
360→    }),
