  1→import type {
  2→  Block,
  3→  CompoundContextSibling,
  4→  CompoundSelector,
  5→  Conversation,
  6→  FormatRule,
  7→} from "@chat-exporter/shared";
  8→import { ruleSelectorSchema } from "@chat-exporter/shared";
  9→
 10→import { blockToPlainText } from "./reader-block-render";
 11→
 12→export type ReaderMatchContext = {
 13→  messageRole: string;
 14→  blocks: Block[];
 15→};
 16→
 17→export function matchesReaderRule(
 18→  rule: FormatRule,
 19→  messageId: string,
 20→  blockIndex: number,
 21→  blockType: Block["type"],
 22→  blockText: string,
 23→  context?: ReaderMatchContext,
 24→) {
 25→  const parsed = ruleSelectorSchema.safeParse(rule.selector);
 26→
 27→  if (!parsed.success) {
 28→    return false;
 29→  }
 30→
 31→  const selector = parsed.data;
 32→
 33→  if ("strategy" in selector && selector.strategy === "compound") {
 34→    return matchesCompoundSelector(
 35→      selector,
 36→      blockType,
 37→      blockText,
 38→      blockIndex,
 39→      context,
 40→    );
 41→  }
 42→
 43→  if ("strategy" in selector && selector.strategy === "block_type") {
 44→    return selector.blockType === blockType;
 45→  }
 46→
 47→  if ("strategy" in selector && selector.strategy === "prefix_before_colon") {
 48→    return (
 49→      "blockType" in selector &&
 50→      selector.blockType === blockType &&
 51→      /^([^:\n]{1,120}:)(\s*)(.*)$/.test(blockText)
 52→    );
 53→  }
 54→
 55→  // exact match (strategy === "exact")
 56→  return (
 57→    "messageId" in selector &&
 58→    selector.messageId === messageId &&
 59→    "blockIndex" in selector &&
 60→    selector.blockIndex === blockIndex &&
 61→    "blockType" in selector &&
 62→    selector.blockType === blockType
 63→  );
 64→}
 65→
 66→function matchesCompoundSelector(
 67→  selector: CompoundSelector,
 68→  blockType: Block["type"],
 69→  blockText: string,
 70→  blockIndex: number,
 71→  context?: ReaderMatchContext,
 72→): boolean {
 73→  if (selector.blockType !== undefined && selector.blockType !== blockType) {
 74→    return false;
 75→  }
 76→
 77→  if (
 78→    selector.messageRole !== undefined &&
 79→    context !== undefined &&
 80→    selector.messageRole !== context.messageRole
 81→  ) {
 82→    return false;
 83→  }
 84→
 85→  if (selector.headingLevel !== undefined) {
 86→    if (blockType !== "heading") {
 87→      return false;
 88→    }
 89→    if (context !== undefined) {
 90→      const block = context.blocks[blockIndex];
 91→      if (
 92→        block === undefined ||
 93→        block.type !== "heading" ||
 94→        block.level !== selector.headingLevel
 95→      ) {
 96→        return false;
 97→      }
 98→    }
 99→  }
100→
101→  if (selector.position !== undefined && context !== undefined) {
102→    if (selector.position === "first" && blockIndex !== 0) {
103→      return false;
104→    }
105→    if (
106→      selector.position === "last" &&
107→      blockIndex !== context.blocks.length - 1
108→    ) {
109→      return false;
110→    }
111→  }
112→
113→  if (selector.textPattern !== undefined) {
114→    if (!matchesTextPattern(blockText, selector.textPattern)) {
115→      return false;
116→    }
117→  }
118→
119→  if (selector.context !== undefined && context !== undefined) {
120→    if (selector.context.previousSibling !== undefined) {
121→      const prevBlock = context.blocks[blockIndex - 1];
122→      if (!matchesSiblingFilter(prevBlock, selector.context.previousSibling)) {
123→        return false;
124→      }
125→    }
126→
127→    if (selector.context.nextSibling !== undefined) {
128→      const nextBlock = context.blocks[blockIndex + 1];
129→      if (!matchesSiblingFilter(nextBlock, selector.context.nextSibling)) {
130→        return false;
131→      }
132→    }
133→  }
134→
135→  return true;
136→}
137→
138→function matchesTextPattern(text: string, pattern: string): boolean {
139→  try {
140→    return new RegExp(pattern).test(text);
141→  } catch {
142→    return false;
143→  }
144→}
145→
146→function matchesSiblingFilter(
147→  block: Block | undefined,
148→  filter: CompoundContextSibling,
149→): boolean {
150→  if (block === undefined) {
151→    return false;
152→  }
153→
154→  if (filter.blockType !== undefined && block.type !== filter.blockType) {
155→    return false;
156→  }
157→
158→  if (filter.headingLevel !== undefined) {
159→    if (block.type !== "heading" || block.level !== filter.headingLevel) {
160→      return false;
161→    }
162→  }
163→
164→  if (filter.textPattern !== undefined) {
165→    const text =
166→      block.type === "list"
167→        ? block.items.join("\n")
168→        : block.type === "table"
169→          ? [
170→              block.headers.join(" | "),
171→              ...block.rows.map((row) => row.join(" | ")),
172→            ].join("\n")
173→          : block.text;
174→
175→    if (!matchesTextPattern(text, filter.textPattern)) {
176→      return false;
177→    }
178→  }
179→
180→  return true;
181→}
182→
183→export function getBlocksMatchingRule(
184→  rule: FormatRule,
185→  conversation: Conversation,
186→): Array<{ messageId: string; blockIndex: number }> {
187→  const matches: Array<{ messageId: string; blockIndex: number }> = [];
188→
189→  for (const message of conversation.messages) {
190→    const context: ReaderMatchContext = {
191→      messageRole: message.role,
192→      blocks: message.blocks,
193→    };
194→
195→    for (
196→      let blockIndex = 0;
197→      blockIndex < message.blocks.length;
198→      blockIndex += 1
199→    ) {
200→      const block = message.blocks[blockIndex];
201→
202→      if (!block) {
203→        continue;
204→      }
205→
206→      if (
207→        matchesReaderRule(
208→          rule,
209→          message.id,
210→          blockIndex,
211→          block.type,
212→          blockToPlainText(block),
213→          context,
214→        )
215→      ) {
216→        matches.push({ messageId: message.id, blockIndex });
217→      }
218→    }
219→  }
220→
221→  return matches;
222→}
