 66→const os = implement(contract);
 67→
 68→export const router = os.router({
 69→  imports: {
 70→    list: os.imports.list.handler(({ input }) => {
 71→      return listImportJobs(input);
 72→    }),
 73→
 74→    delete: os.imports.delete.handler(({ input }) => {
 75→      const job = getImportJob(input.id);
 76→      if (!job) {
 77→        throw new ORPCError("NOT_FOUND", {
 78→          message: "Import nicht gefunden.",
 79→        });
 80→      }
 81→      const deleted = deleteImportJob(input.id);
 82→      return { deleted };
 83→    }),
 84→
 85→    create: os.imports.create.handler(({ input }) => {
 86→      if (!isSupportedChatGptShareLink(input.url)) {
 87→        throw new ORPCError("BAD_REQUEST", {
 88→          message:
 89→            "Dieser erste Stand akzeptiert nur öffentliche ChatGPT-Share-Links.",
 90→        });
 91→      }
 92→
 93→      const job = createImportJob(input);
 94→      void runImportJob(job.id);
 95→      return job;
 96→    }),
 97→
 98→    get: os.imports.get.handler(({ input }) => {
 99→      const job = getImportJob(input.id);
100→
101→      if (!job) {
102→        throw new ORPCError("NOT_FOUND", {
103→          message: "Import nicht gefunden.",
104→        });
105→      }
106→
107→      return job;
108→    }),
109→
110→    snapshot: os.imports.snapshot.handler(({ input }) => {
111→      const snapshot = getPersistedImportSnapshot(input.id);
112→
113→      if (!snapshot) {
114→        throw new ORPCError("NOT_FOUND", {
115→          message: "Import-Snapshot nicht gefunden.",
116→        });
117→      }
118→
119→      const rawHtmlPreview = snapshot.rawHtml.slice(0, RAW_HTML_PREVIEW_LENGTH);
120→
121→      return importSnapshotSchema.parse({
122→        importId: snapshot.importId,
123→        sourceUrl: snapshot.sourceUrl,
124→        finalUrl: snapshot.finalUrl,
125→        fetchedAt: snapshot.fetchedAt,
126→        pageTitle: snapshot.pageTitle,
127→        rawHtmlBytes: Buffer.byteLength(snapshot.rawHtml, "utf8"),
128→        rawHtmlPreview,
129→        rawHtmlTruncated: snapshot.rawHtml.length > rawHtmlPreview.length,
130→        normalizedPayload: snapshot.normalizedPayload,
131→        fetchMetadata: snapshot.fetchMetadata,
132→      });
133→    }),
134→
135→    rawHtml: os.imports.rawHtml.handler(({ input }) => {
136→      const snapshot = getPersistedImportSnapshot(input.id);
137→
138→      if (!snapshot) {
139→        throw new ORPCError("NOT_FOUND", {
140→          message: "Import-Snapshot nicht gefunden.",
141→        });
142→      }
143→
144→      return snapshot.rawHtml;
145→    }),
146→
147→    // Design-Entscheidung: Dieser Endpoint liefert absichtlich rohe, unveränderte
148→    // Artefakte ohne angewendete Format-Rules. Client-seitiger Markdown-Download
149→    // verwendet stattdessen `displayedMarkdown` (mit `applyMarkdownRules` inkl.
150→    // format_profile-Rules). Änderungen hier dürfen diese Trennung nicht aufheben.
151→    exportArtifact: os.imports.exportArtifact.handler(({ input }) => {
152→      const job = getImportJob(input.id);
153→
154→      if (!job || !job.artifacts) {
155→        throw new ORPCError("NOT_FOUND", {
156→          message: "Export-Artefakt nicht gefunden.",
157→        });
158→      }
159→
160→      switch (input.format) {
161→        case "markdown":
162→          return job.artifacts.markdown;
163→        case "handover":
164→          return job.artifacts.handover;
165→        case "json":
166→          return job.artifacts.json;
167→        default:
168→          throw new ORPCError("BAD_REQUEST", {
169→            message: "Nicht unterstütztes Exportformat.",
170→          });
171→      }
172→    }),
173→  },
174→
175→  adjustments: {
176→    listSessions: os.adjustments.listSessions.handler(({ input }) => {
177→      const job = getImportJob(input.importId);
178→
179→      if (!job) {
180→        throw new ORPCError("NOT_FOUND", {
181→          message: "Import nicht gefunden.",
182→        });
183→      }
184→
185→      return listAdjustmentSessions(input.importId, input.format);
186→    }),
187→
188→    createSession: os.adjustments.createSession.handler(({ input }) => {
189→      const job = getImportJob(input.importId);
190→
191→      if (!job) {
192→        throw new ORPCError("NOT_FOUND", {
193→          message: "Import nicht gefunden.",
194→        });
195→      }
196→
197→      const { session } = createAdjustmentSession({
198→        importId: input.importId,
199→        selection: input.selection,
200→        targetFormat: input.targetFormat,
201→      });
202→      const detail = getAdjustmentSessionDetail(session.id);
203→
204→      if (!detail) {
205→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
206→          message: "Anpassungssession konnte nicht geladen werden.",
207→        });
208→      }
209→
210→      return detail;
211→    }),
212→
213→    getSession: os.adjustments.getSession.handler(({ input }) => {
214→      const detail = getAdjustmentSessionDetail(input.id);
215→
216→      if (!detail) {
217→        throw new ORPCError("NOT_FOUND", {
218→          message: "Anpassungssession nicht gefunden.",
219→        });
220→      }
221→
222→      return detail;
223→    }),
224→
225→    appendMessage: os.adjustments.appendMessage.handler(async ({ input }) => {
226→      const detail = getAdjustmentSessionDetail(input.sessionId);
227→
228→      if (!detail) {
229→        throw new ORPCError("NOT_FOUND", {
230→          message: "Anpassungssession nicht gefunden.",
231→        });
232→      }
233→
234→      // Phase 1 — Transaction: reopen (if needed) + append user message + reload detail
235→      const latestDetail = withTransaction(() => {
236→        const freshDetail = getAdjustmentSessionDetail(input.sessionId);
237→
238→        if (!freshDetail) {
239→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
240→            message: "Anpassungssession konnte nicht neu geladen werden.",
241→          });
242→        }
243→
244→        if (freshDetail.session.status === "applied") {
245→          reopenAdjustmentSession(input.sessionId);
246→        }
247→
248→        appendAdjustmentMessage(input.sessionId, "user", input.content);
249→
250→        const reloaded = getAdjustmentSessionDetail(input.sessionId);
251→
252→        if (!reloaded) {
253→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
254→            message: "Anpassungssession konnte nicht neu geladen werden.",
255→          });
256→        }
257→
258→        return reloaded;
259→      });
260→
261→      const activeRules = listFormatRules(
262→        detail.session.importId,
263→        detail.session.targetFormat,
264→      ).filter((rule: { status: string }) => rule.status === "active");
265→
266→      // Phase 2 — no wrapper: async AI call
267→      try {
268→        const job = getImportJob(detail.session.importId);
269→        const result = await runAgentTurn({
270→          sessionDetail: latestDetail,
271→          activeRules,
272→          job,
273→          callbacks: {
274→            onCreateRule: async ({ selector, effect, description }) => {
275→              const rule = createFormatRuleDirect({
276→                importId: latestDetail.session.importId,
277→                targetFormat: latestDetail.session.targetFormat,
278→                selector,
279→                effect: {
280→                  type: "custom_style" as const,
281→                  ...effect,
282→                  description,
283→                },
284→                instruction: description,
285→                sourceSessionId: input.sessionId,
286→              });
287→              return { ruleId: rule.id };
288→            },
289→            onUpdateRule: async ({ ruleId, effect, description }) => {
290→              updateFormatRuleEffect(
291→                ruleId,
292→                { type: "custom_style" as const, ...effect, description },
293→                description,
294→              );
295→            },
296→            onDeleteRule: async (ruleId) => {
297→              disableFormatRule(ruleId, latestDetail.session.importId);
298→            },
299→          },
300→        });
301→
302→        // Phase 3 — persist assistant message + events
303→        withTransaction(() => {
304→          appendAdjustmentMessage(
305→            input.sessionId,
306→            "assistant",
307→            result.assistantMessage,
308→          );
309→
310→          for (const action of result.actions) {
311→            recordAdjustmentEvent({
312→              importId: latestDetail.session.importId,
313→              ruleId: action.ruleId,
314→              sessionId: input.sessionId,
315→              targetFormat: latestDetail.session.targetFormat,
316→              type:
317→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
318→            });
319→          }
320→
321→          if (result.actions.length > 0) {
322→            markSessionApplied(input.sessionId);
323→          } else {
324→            recordAdjustmentEvent({
325→              importId: latestDetail.session.importId,
326→              sessionId: input.sessionId,
327→              targetFormat: latestDetail.session.targetFormat,
328→              type: "clarification_requested",
329→            });
330→          }
331→        });
332→      } catch (error) {
333→        if (error instanceof AgentUnavailableError) {
334→          throw new ORPCError("SERVICE_UNAVAILABLE", {
335→            message: error.message,
336→          });
337→        }
338→        if (error instanceof DOMException && error.name === "TimeoutError") {
339→          throw new ORPCError("GATEWAY_TIMEOUT", {
340→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
341→          });
342→        }
343→        throw new ORPCError("BAD_REQUEST", {
344→          message:
345→            error instanceof Error
346→              ? error.message
347→              : "Die Live-KI-Nachricht konnte nicht verarbeitet werden.",
348→        });
349→      }
350→
351→      const nextDetail = getAdjustmentSessionDetail(input.sessionId);
352→
353→      if (!nextDetail) {
354→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
355→          message: "Anpassungssession konnte nicht neu geladen werden.",
356→        });
357→      }
358→
359→      return nextDetail;
360→    }),
361→
362→    discard: os.adjustments.discard.handler(({ input }) => {
363→      try {
