366→export function discardAdjustmentSession(sessionId: string) {
367→  const session = getAdjustmentSession(sessionId);
368→
369→  if (!session) {
370→    throw new Error("Anpassungssession nicht gefunden.");
371→  }
372→
373→  if (session.status === "applied") {
374→    throw new Error(
375→      "Bereits angewendete Anpassungssessions können nicht verworfen werden.",
376→    );
377→  }
378→
379→  if (session.status === "discarded") {
380→    throw new Error("Diese Anpassungssession wurde bereits verworfen.");
381→  }
382→
383→  const timestamp = now();
384→
385→  db.transaction((tx) => {
386→    const result = tx
387→      .update(adjustmentSessions)
388→      .set({
389→        status: "discarded",
390→        updatedAt: timestamp,
391→      })
392→      .where(
393→        and(
394→          eq(adjustmentSessions.id, sessionId),
395→          inArray(adjustmentSessions.status, ["open"]),
396→        ),
397→      )
398→      .run();
399→
400→    if (result.changes === 0) {
401→      throw new Error(
402→        "Status-Transition fehlgeschlagen: Session ist nicht mehr in einem verwerfbaren Zustand.",
403→      );
404→    }
405→
406→    recordAdjustmentEvent(
407→      {
408→        importId: session.importId,
409→        sessionId: session.id,
410→        targetFormat: session.targetFormat,
411→        type: "session_discarded",
412→      },
413→      tx,
414→    );
415→  });
416→
417→  const nextDetail = getAdjustmentSessionDetail(sessionId);
418→
419→  if (!nextDetail) {
420→    throw new Error("Anpassungssession konnte nicht neu geladen werden.");
421→  }
422→
423→  return nextDetail;
424→}
