test("concurrent calls both resolve to true after creation completes", async () => {
  // Arrange: creation takes time; second call arrives while first is in-flight
  let resolveCreate!: (value: { id: string; label: string; isActive: boolean }) => void;
  createMock.mockImplementation(
    () =>
      new Promise((resolve) => {
        resolveCreate = resolve;
      }),
  );

  const { result } = renderHook(() =>
    useAutoSnapshot({
      activeSnapshot: null,
      create: createMock,
      activate: activateMock,
    }),
  );

  let results: boolean[] = [];
  await act(async () => {
    // Both calls fired before any await — second sees creation in-progress
    const p1 = result.current.ensureSnapshot();
    const p2 = result.current.ensureSnapshot();

    // Now let creation finish
    resolveCreate({ id: "snap-new", label: "Bearbeitet", isActive: false });

    results = await Promise.all([p1, p2]);
  });

  // Both callers must receive true — if second returned true prematurely
  // (before activation), the caller would try saveEdit while snapshotId is
  // still undefined, silently losing the edit.
  expect(results[0]).toBe(true);
  expect(results[1]).toBe(true);
  expect(activateMock).toHaveBeenCalledTimes(1);
});

