  test("concurrent second call waits for activation before resolving true", async () => {
    // Arrange: creation and activation are both deferred so we can observe
    // the precise moment p2 resolves relative to activation completing.
    let resolveCreate!: (value: {
      id: string;
      label: string;
      isActive: boolean;
    }) => void;
    let resolveActivate!: () => void;

    createMock.mockImplementation(
      () =>
        new Promise((resolve) => {
          resolveCreate = resolve;
        }),
    );
    activateMock.mockImplementation(
      () =>
        new Promise<void>((resolve) => {
          resolveActivate = resolve;
        }),
    );

    const { result } = renderHook(() =>
      useAutoSnapshot({
        activeSnapshot: null,
        create: createMock,
        activate: activateMock,
      }),
    );

    // Both calls fired concurrently — p2 hits the in-progress guard
    const p1 = result.current.ensureSnapshot();
    const p2 = result.current.ensureSnapshot();

    // Resolve creation so activate() starts
    resolveCreate({ id: "snap-new", label: "Bearbeitet", isActive: false });

    // Flush microtasks so activate is called
    await Promise.resolve();
    await Promise.resolve();

    // p2 must NOT have resolved yet — activation is still pending.
    // With the buggy boolean-ref implementation, p2 returned true immediately
    // when it saw creatingRef.current === true, before activate() finished.
    // That left snapshotId undefined in the caller, silently dropping the edit.
    let p2Resolved = false;
    void p2.then(() => {
      p2Resolved = true;
    });

    // Flush microtasks — p2 should still be pending
    await Promise.resolve();
    await Promise.resolve();

    expect(p2Resolved).toBe(false);

    // Now finish activation — both callers should resolve to true
    resolveActivate();

    const [r1, r2] = await Promise.all([p1, p2]);

    expect(r1).toBe(true);
    expect(r2).toBe(true);
    expect(activateMock).toHaveBeenCalledTimes(1);
  });

  test("returns false when snapshot creation fails", async () => {
    createMock.mockRejectedValue(new Error("Network error"));

    const { result } = renderHook(() =>
      useAutoSnapshot({
        activeSnapshot: null,
        create: createMock,
        activate: activateMock,
      }),
    );

    let snapshotReady: boolean | undefined;
    await act(async () => {
      snapshotReady = await result.current.ensureSnapshot();
    });

    expect(snapshotReady).toBe(false);
  });
});

