 1→import type { ConversationSnapshot } from "@chat-exporter/shared";
 2→import { useCallback, useRef } from "react";
 3→
 4→type UseAutoSnapshotOptions = {
 5→  activeSnapshot: ConversationSnapshot | null;
 6→  create: (label: string) => Promise<ConversationSnapshot>;
 7→  activate: (snapshotId: string) => Promise<unknown>;
 8→};
 9→
10→/**
11→ * Ensures a snapshot exists and is active before an edit is saved.
12→ * On the first edit (when no snapshot is active), automatically creates
13→ * a "Bearbeitet" snapshot and activates it.
14→ *
15→ * Concurrent calls are safe: if creation is already in-flight, subsequent
16→ * callers await the same Promise rather than returning true prematurely.
17→ */
18→export function useAutoSnapshot({
19→  activeSnapshot,
20→  create,
21→  activate,
22→}: UseAutoSnapshotOptions) {
23→  const creatingPromiseRef = useRef<Promise<boolean> | null>(null);
24→
25→  const ensureSnapshot = useCallback(async (): Promise<boolean> => {
26→    if (activeSnapshot) return true;
27→
28→    // If creation is already in-flight, wait for the same Promise.
29→    // This prevents the race condition where a concurrent caller would return
30→    // true before activate() completes, leaving snapshotId undefined in the
31→    // caller and causing saveEdit to silently discard the edit.
32→    if (creatingPromiseRef.current) return creatingPromiseRef.current;
33→
34→    const promise = (async () => {
35→      try {
36→        const snapshot = await create("Bearbeitet");
37→        await activate(snapshot.id);
38→        return true;
39→      } catch {
40→        return false;
41→      } finally {
42→        creatingPromiseRef.current = null;
43→      }
44→    })();
45→
46→    creatingPromiseRef.current = promise;
47→    return promise;
48→  }, [activeSnapshot, create, activate]);
49→
50→  return { ensureSnapshot };
51→}
52→

